mapper.select:
select goods.*, category.name as categoryName from goods left join category on goods.category_id = category.id
and goods.name like concat('%', #{name}, '%') and goods.category_id = #{categoryId}
order by goods.id desc

mapper.update:
update goods set name = #{name}, img = #{img}, descr = #{descr}, specials = #{specials}, price = #{price},
unit = #{unit}, store = #{store}, category_id = #{categoryId}
where id = #{id}
